import{_ as i,o as t,c as r,a2 as n}from"./chunks/framework.Cuq8tsM6.js";const g=JSON.parse('{"title":"2. Tracking & Envoi","description":"","frontmatter":{"title":"2. Tracking & Envoi"},"headers":[],"relativePath":"docs/fr/publishers/dedicated-email/2-tracking-sending.md","filePath":"docs/fr/publishers/dedicated-email/2-tracking-sending.md"}'),o={name:"docs/fr/publishers/dedicated-email/2-tracking-sending.md"};function a(s,e,d,l,p,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="etape-2-tracking-validation-et-envoi" tabindex="-1">Étape 2 : Tracking, Validation et Envoi <a class="header-anchor" href="#etape-2-tracking-validation-et-envoi" aria-label="Permalink to &quot;Étape 2 : Tracking, Validation et Envoi&quot;">​</a></h1><p>Votre maquette est prête ? Intégrez le tracking, soumettez un BAT conforme et gérez la diffusion (et le renvoi éventuel).</p><hr><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3>Intégration du Tracking</h3><p>Rendez-vous dans l&#39;onglet <strong>&quot;Configuration&quot;</strong> de la campagne pour récupérer les tags.</p><div style="display:grid;grid-template-columns:repeat(auto-fit, minmax(250px, 1fr));gap:15px;margin-top:15px;"><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--gi-accent);padding:15px;border-radius:6px;"><strong>👁️ Pixel d&#39;Ouverture</strong><br> Tag image <code>&lt;img...&gt;</code> à coller dans le HTML (avant <code>&lt;/body&gt;</code>).<br><em>Indispensable pour compter les vues.</em></div><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--gi-accent);padding:15px;border-radius:6px;"><strong>🔗 Liens Trackés</strong><br> Remplacez <strong>TOUS</strong> les liens vers l&#39;Annonceur par les liens <code>gtinsi.de</code> fournis.<br><em>Indispensable pour compter les clics.</em></div></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-accent);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3>Validation (BAT)</h3><p>Pour valider la qualité technique, nous utilisons un viewer interne. Le BAT doit respecter un protocole strict.</p><div style="background-color:var(--vp-c-bg-elv);border:2px solid var(--gi-accent);padding:20px;border-radius:8px;"><strong>📧 Procédure d&#39;envoi du BAT</strong><ol><li>Envoyez un <strong>email de test réel</strong> (depuis votre routeur).</li><li>Destinataire unique : <code>benoit+news@getinside.fr</code></li></ol><hr style="margin:15px 0;border-color:var(--vp-c-divider);"><p><strong>⚠️ Attention :</strong> Nous ne validons <strong>jamais</strong> de BAT sous forme de capture d&#39;écran, de PDF ou de fichier HTML brut. Nous devons recevoir l&#39;email pour tester le responsive, le pixel et les redirections en conditions réelles. </p></div><div style="margin-top:20px;"><p>Une fois le BAT reçu et vérifié par getinside :</p><ul><li>Nous générons un lien de prévisualisation (BAT Statique).</li><li><strong>Action Bloquante :</strong> Connectez-vous à la plateforme et cliquez sur <strong>&quot;Valider la campagne&quot;</strong>.</li><li>Attendez que l&#39;Annonceur valide également de son côté.</li></ul></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:var(--gi-tint-green-text);color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3>Diffusion &amp; Renvoi</h3><div style="margin-bottom:20px;"><strong>1. Vérification du Ciblage</strong><br> Avant de router, assurez-vous d&#39;avoir appliqué les critères de segmentation demandés dans le brief (ex: Actifs 12 mois, Femmes, etc.). </div><div style="background:var(--gi-tint-blue-bg);border:1px solid var(--vp-c-divider);padding:20px;border-radius:8px;margin-bottom:20px;"><h4>🔄 Gestion du Renvoi (Non-Ouvreurs)</h4><p>Si un renvoi aux non-ouvreurs (RGNO) est commandé :</p><ul><li>Utilisez <strong>exactement le même email</strong> (Même HTML, mêmes liens, même pixel).</li><li>Ne changez pas les trackers.</li><li>Une fois le renvoi effectué, n&#39;oubliez pas de revenir confirmer cette deuxième diffusion.</li></ul></div><div><strong>2. Confirmation Finale</strong><br> Une fois l&#39;envoi (et le renvoi éventuel) terminé, retournez sur <a href="https://app.getinside.media/">app.getinside.media</a> et cliquez sur le bouton <strong>&quot;Valider la diffusion&quot;</strong> dans l&#39;espace &quot;Configuration et Suivi&quot;. </div></div></div>',6)])])}const v=i(o,[["render",a]]);export{g as __pageData,v as default};
